#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
typedef unsigned long long uLL;
const int N=5e5+10,Base=7;uLL G[N],I[N],pw[N];int n,a[N],pos[N];
inline void add(uLL *t,int x,uLL w){while(x<=n)t[x]=t[x]+w,x+=(x&-x);}
inline uLL qry(uLL *t,int l,int r){--l;uLL res=0;while(r)res=res+t[r],r^=(r&-r);while(l)res=res-t[l],l^=(l&-l);return res;}
inline bool Jud(int l,int r)
{
	int ll=n-r+1,rr=n-l+1;
	return qry(G,l,r)*pw[n-r]==qry(I,ll,rr)*pw[n-rr];
}
int main()
{
	pw[0]=1;rep(1,N-5,i)pw[i]=pw[i-1]*Base;
	
	int T=read();Begin:
		
	n=read();rep(1,n,i)a[i]=read();
	memset(G,0,(n+1)*sizeof(uLL));memset(I,0,(n+1)*sizeof(uLL));
	bool flag=0;rep(1,n,i)
	{
		int dis=min(a[i]-1,n-a[i]);
		if(!Jud(a[i]-dis,a[i]+dis)){flag=true;puts("Y");break;}
		add(G,a[i],pw[a[i]]);add(I,n-a[i]+1,pw[n-a[i]+1]);
	}
	if(!flag)puts("N");
	
	if(--T)goto Begin;return 0;
}
